 33→        setCaptchaError("ReCaptcha is mandatory");
 34→        setLoading(false);
 35→        return;
 36→      }
 37→      window.scrollTo(0, 0);
 38→      const verify = await verifyCaptcha(captchaToken);
 39→      captchaRef.current?.reset();
 40→
 41→      if (verify) {
 42→        const registerationSuccess = await registerUser(formValue);
 43→        setFormValue({
 44→          email: "",
 45→          fullname: "",
 46→          password: "",
